ਸੰਕੇਤ: ਹੇਠਾਂ ਦਿੱਤਾ ਕੋਡ ਦਿਖਾਉਂਦਾ ਹੈ ਕਿ ਲਿਬਆਰਕਾਈਵ ਲਾਇਬ੍ਰੇਰੀ ਨਾਲ ਤਾਰ ਫਾਈਲ ਦੀ ਸਮੱਗਰੀ ਨੂੰ ਦਿੱਤੇ ਗਏ ਟਿਕਾਣੇ ਦੇ ਪਾਥ ਤੱਕ ਕਿਵੇਂ ਕੱ .ਿਆ ਜਾਵੇ।

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

